(32, 10, '20102010', 'Razzib', 'XII XII', 0, '2026-04-28 08:23:51', '[{\"soal_id\":69,\"pertanyaan\":\"Konektor yang umum digunakan pada kabel UTP untuk jaringan komputer adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"RJ-11\",\"opsi_b\":\"RJ-45\",\"opsi_c\":\"BNC\",\"opsi_d\":\"USB\",\"opsi_e\":\"HDMI\"},{\"soal_id\":70,\"pertanyaan\":\"Urutan warna standar T568B untuk kabel UTP dimulai dengan warna...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Hijau Putih\",\"opsi_b\":\"Cokelat Putih\",\"opsi_c\":\"Oranye Putih\",\"opsi_d\":\"Biru Putih\",\"opsi_e\":\"Oranye\"},{\"soal_id\":71,\"pertanyaan\":\"Jenis kabel UTP yang digunakan untuk menghubungkan dua perangkat yang sama (misal komputer ke komputer) secara langsung adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Straight-through\",\"opsi_b\":\"Rollover\",\"opsi_c\":\"Crossover\",\"opsi_d\":\"Fiber Optic\",\"opsi_e\":\"Coaxial\"},{\"soal_id\":72,\"pertanyaan\":\"Alat yang digunakan untuk memotong dan menjepit konektor RJ-45 pada kabel UTP disebut...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"a\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Crimping Tool\",\"opsi_b\":\"Tang Kombinasi\",\"opsi_c\":\"Obeng\",\"opsi_d\":\"Solder\",\"opsi_e\":\"LAN Tester\"},{\"soal_id\":73,\"pertanyaan\":\"Untuk menguji apakah kabel UTP yang telah dikrimping berfungsi dengan baik, alat yang digunakan adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Multimeter\",\"opsi_b\":\"Oscilloscope\",\"opsi_c\":\"LAN Tester\",\"opsi_d\":\"Router\",\"opsi_e\":\"Switch\"},{\"soal_id\":74,\"pertanyaan\":\"Alamat unik dalam bentuk angka yang digunakan untuk mengidentifikasi perangkat di jaringan disebut...\",\"jawaban_siswa\":