ubah\",\"opsi_c\":\"Layanan jaringan tersedia saat dibutuhkan pengguna\",\"opsi_d\":\"Data terenkripsi\",\"opsi_e\":\"Data bisa dihapus siapa saja\"},{\"soal_id\":96,\"pertanyaan\":\"Dalam konfigurasi Wi-Fi, protokol keamanan yang umum digunakan saat ini adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"WEP\",\"opsi_b\":\"WPA2 atau WPA3\",\"opsi_c\":\"HTTP\",\"opsi_d\":\"FTP\",\"opsi_e\":\"SMTP\"},{\"soal_id\":97,\"pertanyaan\":\"Apa risiko utama jika kita menggunakan jaringan Wi-Fi publik yang tidak terenkripsi?\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Sinyal menjadi lebih kuat\",\"opsi_b\":\"Data pribadi mudah disadap atau dicuri\",\"opsi_c\":\"Baterai HP awet\",\"opsi_d\":\"Internet menjadi gratis selamanya\",\"opsi_e\":\"Laptop menjadi lebih cepat\"},{\"soal_id\":98,\"pertanyaan\":\"Tindakan pencegahan untuk menjaga ketersediaan data jika terjadi kerusakan sistem atau serangan adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Formatting\",\"opsi_b\":\"Deleting\",\"opsi_c\":\"Melakukan Backup data\",\"opsi_d\":\"Editing\",\"opsi_e\":\"Copying\"}]', NULL, NULL, 0, NULL),
