10,\"poin_diperoleh\":0,\"opsi_a\":\"3 Lapis\",\"opsi_b\":\"4 Lapis\",\"opsi_c\":\"5 Lapis\",\"opsi_d\":\"7 Lapis\",\"opsi_e\":\"8 Lapis\"},{\"soal_id\":45,\"pertanyaan\":\"Media transmisi yang menggunakan cahaya untuk mengirimkan data adalah...\",\"jawaban_siswa\":\"a\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Kabel Coaxial\",\"opsi_b\":\"Kabel UTP\",\"opsi_c\":\"Fiber Optic\",\"opsi_d\":\"Kabel STP\",\"opsi_e\":\"Kabel Tembaga\"},{\"soal_id\":46,\"pertanyaan\":\"Contoh media transmisi tanpa kabel (wireless) adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Fiber Optic\",\"opsi_b\":\"Kabel UTP\",\"opsi_c\":\"Gelombang Radio\",\"opsi_d\":\"Kabel Coaxial\",\"opsi_e\":\"Twisted Pair\"},{\"soal_id\":47,\"pertanyaan\":\"Apa satuan kecepatan transmisi data?\",\"jawaban_siswa\":\"c\",\"kunci_jawaban\":\"c\",\"is_correct\":true,\"poin\":10,\"poin_diperoleh\":10,\"opsi_a\":\"Hertz\",\"opsi_b\":\"Volt\",\"opsi_c\":\"Bits per second (bps)\",\"opsi_d\":\"Watt\",\"opsi_e\":\"Ohm\"},{\"soal_id\":48,\"pertanyaan\":\"Sinyal yang bersifat kontinu dan bervariasi terhadap waktu disebut sinyal...\",\"jawaban_siswa\":\"b\",\"kunci_jawaban\":\"b\",\"is_correct\":true,\"poin\":10,\"poin_diperoleh\":10,\"opsi_a\":\"Digital\",\"opsi_b\":\"Analog\",\"opsi_c\":\"Biner\",\"opsi_d\":\"Paket\",\"opsi_e\":\"Switching\"},{\"soal_id\":49,\"pertanyaan\":\"Sinyal yang hanya memiliki dua keadaan, yaitu 0 dan 1, disebut sinyal...\",\"jawaban_siswa\":\"a\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Analog\",\"opsi_b\":\"Digital\",\"opsi_c\":\"Gelombang\",\"opsi_d\":\"Kontinu\",\"opsi_e\":\"Modulasi\"},{\"soal_id\":50,\"pertanyaan\":\"Satuan terkecil dari data yang dikirimkan melalui jaringan komputer disebut...\",\"jawaban_siswa\":\"c\",\"kunci_jawaban\":\"c\",\"is_correct\":true,\"poin\":10,\"poin_diperoleh\":10,\"opsi_a\":\"Frame\",\"opsi_b\":\"Segment\",\"opsi_c\":\"Paket Data\",\"opsi_d\":\"Bit\",\"opsi_e\":\"Byte\"},{\"soal_id\":51,\"pertanyaan\":\"Bagian dari struktur paket data yang berisi alamat pengirim dan penerima disebut...\",\"jawaban_siswa\":\"b\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Payload\",\"opsi_b\":\"Trailer\",\"opsi_c\":\"Header\",\"opsi_d\":\"Footer\",\"opsi_e\":\"Data\"},{\"soal_id\":52,\"pertanyaan\":\"Metode pengiriman data di mana pesan dipecah menjadi potongan-potongan kecil disebut...\",\"jawaban_siswa\":\"c\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Circuit Switching\",\"opsi_b\":\"Packet Switching\",\"opsi_c\":\"Line Switching\",\"opsi_d\":\"Data Switching\",\"opsi_e\":\"Manual Switching\"},{\"soal_id\":53,\"pertanyaan\":\"Perangkat yang berfungsi untuk menghubungkan beberapa jaringan yang berbeda adalah...\",\"jawaban_siswa\":\"d\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Hub\",\"opsi_b\":\"Switch\",\"opsi_c\":\"Router\",\"opsi_d\":\"Repeater\",\"opsi_e\":\"Bridge\"},{\"soal_id\":54,\"pertanyaan\":\"Perangkat yang berfungsi memperkuat sinyal dalam kabel jaringan adalah...\",\"jawaban_siswa\":\"b\",\"kunci_jawaban\":\"b\",\"is_correct\":true,\"poin\":10,\"poin_diperoleh\":10,\"opsi_a\":\"Router\",\"opsi_b\":\"Repeater\",\"opsi_c\":\"Modem\",\"opsi_d\":\"Switch\",\"opsi_e\":\"NIC\"},{\"soal_id\":55,\"pertanyaan\":\"Kabel UTP biasanya menggunakan konektor tipe...\",\"jawaban_siswa\":\"c\",\"kunci_jawaban\":\"c\",\"is_correct\":true,\"poin\":10,\"poin_diperoleh\":10,\"opsi_a\":\"RJ-11\",\"opsi_b\":\"BNC\",\"opsi_c\":\"RJ-45\",\"opsi_d\":\"USB\",\"opsi_e\":\"HDMI\"},{\"soal_id\":56,\"pertanyaan\":\"Alamat unik yang diberikan pada setiap perangkat yang terhubung ke jaringan internet disebut...\",\"jawaban_siswa\":\"c\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"MAC Address\",\"opsi_b\":\"IP Address\",\"opsi_c\":\"Home Address\",\"opsi_d\":\"Email Address\",\"opsi_e\":\"Web Address\"},{\"soal_id\":57,\"pertanyaan\":\"Apa kepanjangan dari LAN?\",\"jawaban_siswa\":\"d\",\"kunci_jawaban\":\"a\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Local Area Network\",\"opsi_b\":\"Long Area Network\",\"opsi_c\":\"Link Area Network\",\"opsi_d\":\"Local Access Network\",\"opsi_e\":\"List Area Network\"},{\"soal_id\":58,\"pertanyaan\":\"Topologi yang setiap komputernya terhubung ke semua komputer lain secara langsung adalah...\",\"jawaban_siswa\":\"a\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Topologi Star\",\"opsi_b\":\"Topologi Bus\",\"opsi_c\":\"Topologi Mesh\",\"opsi_d\":\"Topologi Ring\",\"opsi_e\":\"Topologi Tree\"},{\"soal_id\":59,\"pertanyaan\":\"Lapisan OSI yang bertanggung jawab untuk pengalamatan IP dan routing adalah...\",\"jawaban_siswa\":\"d\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Physical Layer\",\"opsi_b\":\"Network Layer\",\"opsi_c\":\"Session Layer\",\"opsi_d\":\"Presentation Layer\",\"opsi_e\":\"Transport Layer\"},{\"soal_id\":60,\"pertanyaan\":\"Modem adalah singkatan dari...\",\"jawaban_siswa\":\"a\",\"kunci_jawaban\":\"a\",\"is_correct\":true,\"poin\":10,\"poin_diperoleh\":10,\"opsi_a\":\"Modulator Demodulator\",\"opsi_b\":\"Model Demodel\",\"opsi_c\":\"Mode Demode\",\"opsi_d\":\"Modul Demodul\",\"opsi_e\":\"Modern Demodern\"},{\"soal_id\":61,\"pertanyaan\":\"Proses mengubah sinyal digital menjadi analog disebut...\",\"jawaban_siswa\":\"a\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Demodulasi\",\"opsi_b\":\"Modulasi\",\"opsi_c\":\"Transmisi\",\"opsi_d\":\"Switching\",\"opsi_e\":\"Routing\"},{\"soal_id\":62,\"pertanyaan\":\"Kabel jaringan yang terdiri dari dua kawat tembaga yang dipilin adalah...\",\"jawaban_siswa\":\"b\",\"kunci_jawaban\":\"b\",\"is_correct\":true,\"poin\":10,\"poin_diperoleh\":10,\"opsi_a\":\"Fiber Optic\",\"opsi_b\":\"Twisted Pair\",\"opsi_c\":\"Coaxial\",\"opsi_d\":\"Satelit\",\"opsi_e\":\"Inframerah\"},{\"soal_id\":63,\"pertanyaan\":\"Bagian paket data yang berfungsi untuk mengecek kesalahan (error detection) adalah...\",\"jawaban_siswa\":\"c\",\"kunci_jawaban\":\"c\",\"is_correct\":true,\"poin\":10,\"poin_diperoleh\":10,\"opsi_a\":\"Header\",\"opsi_b\":\"Payload\",\"opsi_c\":\"Trailer\\/Checksum\",\"opsi_d\":\"Address\",\"opsi_e\":\"Body\"},{\"soal_id\":64,\"pertanyaan\":\"Keuntungan utama dari Packet Switching adalah...\",\"jawaban_siswa\":\"b\",\"kunci_jawaban\":\"b\",\"is_correct\":true,\"poin\":10,\"poin_diperoleh\":10,\"opsi_a\":\"Jalur komunikasi tetap\",\"opsi_b\":\"Penggunaan bandwidth yang efisien\",\"opsi_c\":\"Hanya satu jalur yang bisa digunakan\",\"opsi_d\":\"Sangat lambat\",\"opsi_e\":\"Mudah disadap\"},{\"soal_id\":65,\"pertanyaan\":\"Perangkat yang mengirimkan data ke port yang spesifik berdasarkan MAC Address adalah...\",\"jawaban_siswa\":\"c\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Hub\",\"opsi_b\":\"Switch\",\"opsi_c\":\"Repeater\",\"opsi_d\":\"Kabel\",\"opsi_e\":\"Antena\"},{\"soal_id\":66,\"pertanyaan\":\"Jaringan komputer dengan skala mencakup satu kota disebut...\",\"jawaban_siswa\":\"a\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"PAN\",\"opsi_b\":\"LAN\",\"opsi_c\":\"MAN\",\"opsi_d\":\"WAN\",\"opsi_e\":\"Internet\"},{\"soal_id\":67,\"pertanyaan\":\"Manakah yang merupakan media transmisi \'Guided\' (terpandu)?\",\"jawaban_siswa\":\"b\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Wi-Fi\",\"opsi_b\":\"Bluetooth\",\"opsi_c\":\"Kabel UTP\",\"opsi_d\":\"Satelit\",\"opsi_e\":\"Infrared\"},{\"soal_id\":68,\"pertanyaan\":\"Lapisan model TCP\\/IP yang setara dengan Physical dan Data Link pada OSI adalah...\",\"jawaban_siswa\":\"c\",\"