(60, 9, '30', 'revallino novansyah', 'XI-8', 20, '2026-04-29 09:29:52', '[{\"soal_id\":39,\"pertanyaan\":\"Apa nama topologi yang menghubungkan semua komputer ke satu titik pusat (hub\\/switch)?\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Topologi Bus\",\"opsi_b\":\"Topologi Star\",\"opsi_c\":\"Topologi Ring\",\"opsi_d\":\"Topologi Mesh\",\"opsi_e\":\"Topologi Tree\"},{\"soal_id\":40,\"pertanyaan\":\"Topologi jaringan yang menggunakan satu kabel tunggal sebagai media transmisi utama disebut...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Topologi Star\",\"opsi_b\":\"Topologi Ring\",\"opsi_c\":\"Topologi Bus\",\"opsi_d\":\"Topologi Mesh\",\"opsi_e\":\"Topologi Hybrid\"},{\"soal_id\":41,\"pertanyaan\":\"Pada topologi Ring, data mengalir dalam bentuk...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Gelombang radio\",\"opsi_b\":\"Token\",\"opsi_c\":\"Sinyal analog\",\"opsi_d\":\"Cahaya\",\"opsi_e\":\"Paket suara\"},{\"soal_id\":42,\"pertanyaan\":\"Model referensi jaringan yang terdiri dari 7 lapisan (layer) adalah model...\",\"jawaban_siswa\":\"a\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"TCP\\/IP\",\"opsi_b\":\"OSI\",\"opsi_c\":\"HTTP\",\"opsi_d\":\"FTP\",\"opsi_e\":\"IEEE\"},{\"soal_id\":43,\"pertanyaan\":\"Lapisan teratas pada model OSI yang berinteraksi langsung dengan pengguna adalah...\",\"jawaban_siswa\":\"d\",\"kunci_jawaban\":\"d\",\"is_correct\":true,\"poin\":10,\"poin_diperoleh\":10,\"opsi_a\":\"Physical Layer\",\"opsi_b\":\"Network Layer\",\"opsi_c\":\"Transport Layer\",\"opsi_d\":\"Application Layer\",\"opsi_e\":\"Data Link Layer\"},{\"soal_id\":44,\"pertanyaan\":\"Model TCP\\/IP memiliki jumlah lapisan sebanyak...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10